INSERT INTO `contract_html_revisions` VALUES (1,97,128,1,'2026-02-16 21:01:21','<!doctype html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"utf-8\">\n  <title>Contract 2026_A_000097</title>\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\">\n  <style>\n    body { font-family: Arial, Helvetica, sans-serif; font-size: 12pt; line-height: 1.35; color: #111; margin: 36px; }\n    h1, h2, h3 { margin: 0 0 10px 0; }\n    h1 { font-size: 18pt; text-align: center; margin-bottom: 18px; }\n    h2 { font-size: 14pt; margin-top: 18px; border-bottom: 1px solid #ccc; padding-bottom: 4px; }\n    p { margin: 8px 0; }\n    .muted { color: #555; }\n    .small { font-size: 10pt; }\n    .hr { border-top: 1px solid #ddd; margin: 14px 0; }\n    table { width: 100%; border-collapse: collapse; margin: 8px 0 0 0; }\n    th, td { padding: 6px 8px; border: 1px solid #ddd; vertical-align: top; }\n    th { background: #f5f5f5; text-align: left; width: 26%; }\n    .two-col { width: 100%; border: none; }\n    .two-col td { border: none; padding: 0; vertical-align: top; }\n    .box { border: 1px solid #ddd; padding: 10px 12px; border-radius: 6px; margin-top: 10px; }\n    .sig-grid { width: 100%; border-collapse: collapse; margin-top: 14px; }\n    .sig-grid td { border: none; padding: 10px 12px; width: 50%; vertical-align: top; }\n    .sig-line { border-bottom: 1px solid #111; height: 18px; margin-top: 26px; }\n    .sig-label { margin-top: 6px; font-size: 10pt; color: #333; }\n    .right { text-align: right; }\n    .center { text-align: center; }\n    .nowrap { white-space: nowrap; }\n  </style>\n</head>\n<body>\n\n<h1>GENERAL SERVICES AGREEMENT</h1>\n\n<p class=\"center muted\">\n  Contract #: <strong>2026_A_000097</strong>\n  &nbsp;&nbsp;|&nbsp;&nbsp;\n  Contract ID: <strong>97</strong>\n  &nbsp;&nbsp;|&nbsp;&nbsp;\n  Status: <strong>draft</strong>\n</p>\n\n<div class=\"hr\"></div>\n\n<h2>1. Parties</h2>\n\n<p>\n  This Agreement (“Agreement”) is entered into by and between:\n</p>\n\n<table>\n  <tr>\n    <th>Owner (Town / Agency)</th>\n    <td>\n      <strong>Town of Holly Springs</strong><br>\n      PO Box 8<br>\n      Phone: 9195572917<br>\n      Email: john.schifano@hollyspringsnc.gov<br>\n      Vendor ID (if any): <br>\n      Company Contact (if any): JOhn Schifano\n    </td>\n  </tr>\n  <tr>\n    <th>Counterparty (Vendor / Provider)</th>\n    <td>\n      <strong>Fake Company, Inc.</strong><br>\n      123 Main Street<br>\n      Phone: 9195572917<br>\n      Email: john.schifano@hollyspringsnc.gov<br>\n      Vendor ID (if any): 1234<br>\n      Company Contact (if any): JOhn Schifano\n    </td>\n  </tr>\n</table>\n\n<h2>2. Contract Summary</h2>\n\n<table>\n  <tr>\n    <th>Contract Name</th>\n    <td>MSA for Pest Control</td>\n  </tr>\n  <tr>\n    <th>Contract Type</th>\n    <td>\n      Change Order<br>\n      <span class=\"muted small\">Change order to existing contract</span>\n    </td>\n  </tr>\n  <tr>\n    <th>Department</th>\n    <td>Administration</td>\n  </tr>\n  <tr>\n    <th>Category / Type (free text)</th>\n    <td></td>\n  </tr>\n  <tr>\n    <th>Term</th>\n    <td>\n      Start Date: <span class=\"nowrap\"></span><br>\n      End Date: <span class=\"nowrap\"></span>\n    </td>\n  </tr>\n  <tr>\n    <th>Auto-Renew</th>\n    <td>\n      No<br>\n      Renewal Term (months): \n    </td>\n  </tr>\n  <tr>\n    <th>Value</th>\n    <td>USD </td>\n  </tr>\n  <tr>\n    <th>Formal Bidding Required</th>\n    <td>No</td>\n  </tr>\n  <tr>\n    <th>Governing Law</th>\n    <td>North Carolina</td>\n  </tr>\n</table>\n\n<h2>3. Points of Contact</h2>\n\n<table>\n  <tr>\n    <th>Owner Primary Contact</th>\n    <td>\n      Lindsay Goldstein<br>\n      Email: lindsay.goldstein@hollyspringsnc.gov<br>\n      Office: <br>\n      Cell: \n    </td>\n  </tr>\n  <tr>\n    <th>Counterparty Primary Contact</th>\n    <td>\n      Susie Link<br>\n      Email: suzi@link.com<br>\n      Office: 9197088082<br>\n      Cell: \n    </td>\n  </tr>\n</table>\n\n<h2>4. Scope of Work</h2>\n\n<div class=\"box\">\n  <p class=\"muted small\" style=\"margin-top:0;\">\n    (Replace the text below with your scope, or rely on the “Description” field.)\n  </p>\n  <p><strong>Description / Scope:</strong></p>\n  <p>Master services agreement for Pest Control for all town facilities (see Exhibit A)</p>\n</div>\n\n<h2>5. Compensation and Payment</h2>\n\n<p>\n  The total not-to-exceed amount under this Agreement is <strong>USD </strong>,\n  unless otherwise amended in writing. Payment shall be made according to the Owner’s standard invoice review and approval process.\n</p>\n\n<h2>6. Term and Termination</h2>\n\n<p>\n  This Agreement begins on <strong></strong> and ends on <strong></strong>, unless terminated earlier\n  in accordance with this section.\n</p>\n\n<p>\n  Either party may terminate this Agreement for convenience upon written notice, subject to any notice requirements and payment\n  for accepted work performed through the effective termination date.\n</p>\n\n<h2>7. Insurance and Indemnification</h2>\n\n<p>\n  Counterparty shall maintain insurance coverage appropriate for the services and shall provide certificates of insurance upon request.\n  To the extent permitted by law, Counterparty shall indemnify and hold harmless the Owner from claims arising out of Counterparty’s\n  negligence or willful misconduct.\n</p>\n\n<h2>8. Compliance with Laws</h2>\n\n<p>\n  Counterparty shall comply with all applicable federal, state, and local laws, ordinances, and regulations related to the performance\n  of this Agreement.\n</p>\n\n<h2>9. Confidentiality (if applicable)</h2>\n\n<p>\n  Each party agrees to protect the other party’s confidential information to the extent disclosed and marked or reasonably understood\n  to be confidential, and to use such information only for purposes of performing under this Agreement.\n</p>\n\n<h2>10. Records and Audit (public contracting)</h2>\n\n<p>\n  Counterparty shall maintain records relating to perform